Hi,

a similar bug was recently fixed in issue #589, now this code seems to fail in the second case label evaluation:


```

module main (in_debug, val);

         function func1;
                 input en;
                 input [31:0] a;
                 func1 = en && (a == 1);
         endfunction

         function func2;
                 input en;
                 input [31:0] a;
                 func2 = en && (a == 2);
         endfunction

         input in_debug;
         integer dbg_addr = 0;
         output integer val;

         initial begin
                 case( 1'b1 )
                 // This line is OK:
                 func1(1'b1, dbg_addr) : val = 1;
                 // This fails:
                 // %Error: Internal Error: test.v:23: ../V3Task.cpp:993: Function not underneath a statement
                 // %Error: Internal Error: See the manual and http://www.veripool.org/verilator for more assistance.
                 func2(1'b1, dbg_addr) : val = 2;
                 default : val = 0;
                 endcase
         end
endmodule


```
